/*
 * Yalnix OS Kernel - COMP 421 Lab 2
 *
 * Implements: KernelStart, SetKernelBrk, trap/interrupt handlers,
 * and all Yalnix kernel calls (Fork, Exec, Exit, Wait, GetPid, Brk,
 * Delay, TtyRead, TtyWrite).
 */

#include <comp421/hardware.h>
#include <comp421/yalnix.h>
#include <comp421/loadinfo.h>
#include <fcntl.h>
#include <unistd.h>
#include <string.h>
#include <stdlib.h>
#include <stdio.h>

/* =====================================================================
 *  Constants
 * ===================================================================== */

#define MAX_PROCS       64
#define MAX_PHYS_PAGES  4096   /* supports up to 16MB of physical memory */

/* Process states */
#define PROC_RUNNING    0
#define PROC_READY      1
#define PROC_BLOCKED    2
#define PROC_ZOMBIE     3

/* =====================================================================
 *  Data Structures
 * ===================================================================== */

/* TTY input line buffer */
struct tty_line {
    char            buf[TERMINAL_MAX_LINE];
    int             len;
    int             pos;        /* next byte to read */
    struct tty_line *next;
};

/* Process Control Block */
struct pcb {
    int             pid;
    int             state;

    SavedContext    ctx;
    int             ctx_valid;  /* 1 if ctx has been initialized */

    /* Region 0 page table for this process */
    struct pte      r0pt[PAGE_TABLE_LEN];

    /* User-mode entry state (set by LoadProgram, used on first run) */
    void            *user_pc;
    void            *user_sp;
    int             user_brk_pg;   /* break in R0 VPN */
    int             user_stk_low;  /* lowest valid user stack VPN */

    int             delay_ticks;
    int             exit_status;

    struct pcb      *parent;
    struct pcb      *next;          /* ready / delay queue link */
    struct pcb      *zombie_list;   /* list of zombie children */
    struct pcb      *zombie_next;

    /* TTY: blocking I/O */
    int             tty_id;
    void            *tty_buf;
    int             tty_len;
    int             tty_wrote;      /* bytes queued for transmit so far (TtyWrite) */
    char            tty_kbuf[TERMINAL_MAX_LINE]; /* kernel copy for TtyWrite */
    struct pcb      *tty_write_next; /* write-queue link (separate from ready queue) */
};

/* =====================================================================
 *  Globals
 * ===================================================================== */

/* Region 1 (kernel) page table - static, shared by all processes */
static struct pte   kernel_pt[PAGE_TABLE_LEN];

/* Physical memory free list (next_pfn[i] = next free page, or -1) */
static int          free_pfn[MAX_PHYS_PAGES];
static int          free_head;      /* head of free list, or -1 */
static int          num_free;

/* Kernel break management */
static void         *kernel_brk;
static int          vm_enabled = 0;

/* Process management */
static struct pcb   proc_pool[MAX_PROCS];
static int          proc_pool_used[MAX_PROCS];

static struct pcb   *current;       /* currently running process */
static struct pcb   *ready_head;    /* ready queue head */
static struct pcb   *ready_tail;    /* ready queue tail */
static struct pcb   *delay_head;    /* delay queue */
static struct pcb   *idle_proc;     /* the idle process */

static int          next_pid = 0;
static int          num_procs = 0;  /* live processes (not counting idle) */
static int          clock_count = 0;/* ticks since current process started */

/* Flag for idle bootstrap */
static volatile int idle_started = 0;

/* TTY state */
static struct pcb   *tty_read_blocked[NUM_TERMINALS];
static struct tty_line *tty_inbuf[NUM_TERMINALS];  /* buffered input lines */
static struct pcb   *tty_write_blocked[NUM_TERMINALS]; /* process waiting */
static int          tty_transmitting[NUM_TERMINALS];   /* active TtyTransmit */

/* =====================================================================
 *  Forward declarations
 * ===================================================================== */

static int          LoadProgram(char *name, char **args, struct pcb *p,
                                ExceptionInfo *info);

static void         kill_current(int exit_status);
static void         TrapKernel(ExceptionInfo *info);
static void         TrapClock(ExceptionInfo *info);
static void         TrapIllegal(ExceptionInfo *info);
static void         TrapMemory(ExceptionInfo *info);
static void         TrapMath(ExceptionInfo *info);
static void         TrapTtyReceive(ExceptionInfo *info);
static void         TrapTtyTransmit(ExceptionInfo *info);
static void         TrapDummy(ExceptionInfo *info);

/* =====================================================================
 *  PCB management
 * ===================================================================== */

static struct pcb *alloc_pcb(void) {
    for (int i = 0; i < MAX_PROCS; i++) {
        if (!proc_pool_used[i]) {
            proc_pool_used[i] = 1;
            memset(&proc_pool[i], 0, sizeof(struct pcb));
            proc_pool[i].pid = next_pid++;
            return &proc_pool[i];
        }
    }
    return NULL;
}

static void free_pcb(struct pcb *p) {
    for (int i = 0; i < MAX_PROCS; i++) {
        if (&proc_pool[i] == p) {
            proc_pool_used[i] = 0;
            return;
        }
    }
}

/* =====================================================================
 *  Physical memory management
 * ===================================================================== */

static void pfn_free(int pfn) {
    if (pfn < 0 || pfn >= MAX_PHYS_PAGES) return;
    free_pfn[pfn] = free_head;
    free_head = pfn;
    num_free++;
}

static int pfn_alloc(void) {
    if (free_head == -1) return -1;
    int pfn = free_head;
    free_head = free_pfn[pfn];
    free_pfn[pfn] = -1;
    num_free--;
    return pfn;
}

/* =====================================================================
 *  Ready queue management
 * ===================================================================== */

static void enqueue_ready(struct pcb *p) {
    p->state = PROC_READY;
    p->next = NULL;
    if (ready_tail == NULL) {
        ready_head = ready_tail = p;
    } else {
        ready_tail->next = p;
        ready_tail = p;
    }
}

static struct pcb *dequeue_ready(void) {
    if (ready_head == NULL) return NULL;
    struct pcb *p = ready_head;
    ready_head = p->next;
    if (ready_head == NULL) ready_tail = NULL;
    p->next = NULL;
    return p;
}

/* =====================================================================
 *  Context switch callback
 * ===================================================================== */

static SavedContext *DoSwitch(SavedContext *ctxp, void *p1, void *p2) {
    struct pcb *old = (struct pcb *)p1;
    struct pcb *newer = (struct pcb *)p2;

    if (old != NULL) {
        old->ctx = *ctxp;
        old->ctx_valid = 1;
    }

    if (newer == NULL) {
        /* Save-only: no actual switch */
        return ctxp;
    }

    /* Switch Region 0 page table */
    WriteRegister(REG_PTR0, (RCS421RegVal)(newer->r0pt));
    WriteRegister(REG_TLB_FLUSH, TLB_FLUSH_0);

    current = newer;
    return &newer->ctx;
}

/*
 * Switch from 'from' to 'to'. Both must have valid ctx (or to == NULL for
 * save-only). 'from' is placed in appropriate queue before calling.
 */
static void do_context_switch(struct pcb *from, struct pcb *to) {
    if (to == NULL) {
        /* Save only */
        ContextSwitch(DoSwitch, &from->ctx, (void *)from, NULL);
        return;
    }
    to->state = PROC_RUNNING;
    ContextSwitch(DoSwitch, &from->ctx, (void *)from, (void *)to);
}

/* =====================================================================
 *  Process termination helper
 * ===================================================================== */

/* Free all Region 0 pages except kernel stack */
static void free_user_pages(struct pcb *p) {
    int ks_low = KERNEL_STACK_BASE >> PAGESHIFT;
    int ks_high = (KERNEL_STACK_LIMIT >> PAGESHIFT) - 1;
    for (int vpn = 0; vpn < PAGE_TABLE_LEN; vpn++) {
        if (vpn >= ks_low && vpn <= ks_high) continue;
        if (p->r0pt[vpn].valid) {
            pfn_free(p->r0pt[vpn].pfn);
            p->r0pt[vpn].valid = 0;
        }
    }
}

/* Free ALL Region 0 pages including kernel stack */
static void free_all_r0_pages(struct pcb *p) {
    for (int vpn = 0; vpn < PAGE_TABLE_LEN; vpn++) {
        if (p->r0pt[vpn].valid) {
            pfn_free(p->r0pt[vpn].pfn);
            p->r0pt[vpn].valid = 0;
        }
    }
}

/* =====================================================================
 *  Pick next process to run
 * ===================================================================== */

static struct pcb *pick_next(void) {
    struct pcb *next = dequeue_ready();
    if (next != NULL) return next;
    return idle_proc;
}


/* =====================================================================
 *  SetKernelBrk
 * ===================================================================== */

int SetKernelBrk(void *addr) {
    if (!vm_enabled) {
        /* Before VM: just track break */
        if ((unsigned long)addr > (unsigned long)kernel_brk) {
            kernel_brk = addr;
        }
        return 0;
    }

    /* After VM: allocate/free physical pages as needed */
    unsigned long new_brk = (unsigned long)UP_TO_PAGE(addr);
    unsigned long cur_brk = (unsigned long)UP_TO_PAGE(kernel_brk);

    if (new_brk == cur_brk) {
        kernel_brk = addr;
        return 0;
    }

    if (new_brk > cur_brk) {
        /* Grow kernel heap */
        unsigned long va = cur_brk;
        while (va < new_brk) {
            int vpn = ((long)va - VMEM_1_BASE) >> PAGESHIFT;
            if (vpn < 0 || vpn >= PAGE_TABLE_LEN) return -1;
            if (!kernel_pt[vpn].valid) {
                int pfn = pfn_alloc();
                if (pfn == -1) return -1;
                kernel_pt[vpn].valid = 1;
                kernel_pt[vpn].kprot = PROT_READ | PROT_WRITE;
                kernel_pt[vpn].uprot = PROT_NONE;
                kernel_pt[vpn].pfn   = pfn;
                WriteRegister(REG_TLB_FLUSH, (RCS421RegVal)va);
            }
            va += PAGESIZE;
        }
    } else {
        /* Shrink kernel heap */
        unsigned long va = new_brk;
        while (va < cur_brk) {
            int vpn = ((long)va - VMEM_1_BASE) >> PAGESHIFT;
            if (vpn >= 0 && vpn < PAGE_TABLE_LEN && kernel_pt[vpn].valid) {
                pfn_free(kernel_pt[vpn].pfn);
                kernel_pt[vpn].valid = 0;
                WriteRegister(REG_TLB_FLUSH, (RCS421RegVal)va);
            }
            va += PAGESIZE;
        }
    }

    kernel_brk = addr;
    return 0;
}

/* =====================================================================
 *  LoadProgram
 * ===================================================================== */

/*
 * Load a program from the Linux file 'name' into process p's Region 0.
 * Sets p->user_pc, p->user_sp, p->user_brk_pg, p->user_stk_low.
 * If info != NULL, also sets info->pc, info->sp, info->psr, info->regs.
 *
 * Returns 0 on success, -1 on error (process still runnable),
 * -2 on error (process Region 0 destroyed).
 */
static int LoadProgram(char *name, char **args, struct pcb *p,
                       ExceptionInfo *info)
{
    int fd;
    int status;
    struct loadinfo li;
    char *cp, *cp2, **cpp;
    char *argbuf;
    int i;
    unsigned long argcount;
    int size;
    int text_npg, data_bss_npg, stack_npg;

    TracePrintf(1, "LoadProgram '%s'\n", name);

    if ((fd = open(name, O_RDONLY)) < 0) {
        TracePrintf(0, "LoadProgram: can't open '%s'\n", name);
        return -1;
    }

    status = LoadInfo(fd, &li);
    switch (status) {
    case LI_SUCCESS:
        break;
    case LI_FORMAT_ERROR:
        TracePrintf(0, "LoadProgram: '%s' not in Yalnix format\n", name);
        close(fd);
        return -1;
    default:
        TracePrintf(0, "LoadProgram: '%s' error %d\n", name, status);
        close(fd);
        return -1;
    }

    /* Figure out argument sizes */
    size = 0;
    for (i = 0; args[i] != NULL; i++) size += strlen(args[i]) + 1;
    argcount = i;

    cp = argbuf = (char *)malloc(size + 1);
    if (argbuf == NULL) { close(fd); return -1; }
    for (i = 0; args[i] != NULL; i++) {
        strcpy(cp, args[i]);
        cp += strlen(cp) + 1;
    }

    cp  = ((char *)USER_STACK_LIMIT) - size;
    cpp = (char **)((unsigned long)cp & ~(unsigned long)0xF);
    cpp = (char **)((unsigned long)cpp - ((argcount + 4) * sizeof(void *)));

    text_npg     = li.text_size >> PAGESHIFT;
    data_bss_npg = UP_TO_PAGE(li.data_size + li.bss_size) >> PAGESHIFT;
    stack_npg    = (USER_STACK_LIMIT - DOWN_TO_PAGE(cpp)) >> PAGESHIFT;

    TracePrintf(1, "LoadProgram: text=%d data_bss=%d stack=%d pages\n",
                text_npg, data_bss_npg, stack_npg);

    /* Check virtual space */
    if (MEM_INVALID_PAGES + text_npg + data_bss_npg + 1 + stack_npg +
        1 + KERNEL_STACK_PAGES > PAGE_TABLE_LEN) {
        TracePrintf(0, "LoadProgram: '%s' too large for virtual memory\n", name);
        free(argbuf);
        close(fd);
        return -1;
    }

    /* Count pages this process currently owns (to free) */
    int ks_low  = KERNEL_STACK_BASE >> PAGESHIFT;
    int ks_high = (KERNEL_STACK_LIMIT >> PAGESHIFT) - 1;
    int cur_pages = 0;
    for (int vpn = 0; vpn < PAGE_TABLE_LEN; vpn++) {
        if (vpn >= ks_low && vpn <= ks_high) continue;
        if (p->r0pt[vpn].valid) cur_pages++;
    }

    /* Check physical space */
    int need = text_npg + data_bss_npg + stack_npg;
    if (num_free + cur_pages < need) {
        TracePrintf(0, "LoadProgram: '%s' not enough physical memory\n", name);
        free(argbuf);
        close(fd);
        return -1;
    }

    /* Save sp for use after we destroy Region 0 */
    p->user_sp = (void *)cpp;
    if (info) info->sp = (void *)cpp;

    /* Free old user pages */
    free_user_pages(p);
    WriteRegister(REG_TLB_FLUSH, TLB_FLUSH_0);

    /* --- Build new page table --- */

    /* First MEM_INVALID_PAGES: leave invalid */

    /* Text pages */
    for (i = 0; i < text_npg; i++) {
        int vpn = MEM_INVALID_PAGES + i;
        int pfn = pfn_alloc();
        if (pfn == -1) goto no_mem;
        p->r0pt[vpn].valid = 1;
        p->r0pt[vpn].kprot = PROT_READ | PROT_WRITE;
        p->r0pt[vpn].uprot = PROT_READ | PROT_EXEC;
        p->r0pt[vpn].pfn   = pfn;
    }

    /* Data+BSS pages */
    for (i = 0; i < data_bss_npg; i++) {
        int vpn = MEM_INVALID_PAGES + text_npg + i;
        int pfn = pfn_alloc();
        if (pfn == -1) goto no_mem;
        p->r0pt[vpn].valid = 1;
        p->r0pt[vpn].kprot = PROT_READ | PROT_WRITE;
        p->r0pt[vpn].uprot = PROT_READ | PROT_WRITE;
        p->r0pt[vpn].pfn   = pfn;
    }

    /* Stack pages (at top of user area, below kernel stack red zone) */
    {
        int stack_top_vpn = (USER_STACK_LIMIT >> PAGESHIFT) - 1;
        for (i = 0; i < stack_npg; i++) {
            int vpn = stack_top_vpn - i;
            int pfn = pfn_alloc();
            if (pfn == -1) goto no_mem;
            p->r0pt[vpn].valid = 1;
            p->r0pt[vpn].kprot = PROT_READ | PROT_WRITE;
            p->r0pt[vpn].uprot = PROT_READ | PROT_WRITE;
            p->r0pt[vpn].pfn   = pfn;
        }
        p->user_stk_low = stack_top_vpn - stack_npg + 1;
    }

    /* Set user break: end of data+bss */
    p->user_brk_pg = MEM_INVALID_PAGES + text_npg + data_bss_npg;

    /* Flush TLB so we can read into new pages */
    WriteRegister(REG_TLB_FLUSH, TLB_FLUSH_0);

    /* Read text + data from file */
    if (read(fd, (void *)MEM_INVALID_SIZE, li.text_size + li.data_size)
        != (int)(li.text_size + li.data_size)) {
        TracePrintf(0, "LoadProgram: read failed for '%s'\n", name);
        free(argbuf);
        close(fd);
        return -2;
    }
    close(fd);

    /* Set text pages to read+exec */
    for (i = 0; i < text_npg; i++) {
        int vpn = MEM_INVALID_PAGES + i;
        p->r0pt[vpn].kprot = PROT_READ | PROT_EXEC;
        WriteRegister(REG_TLB_FLUSH, (RCS421RegVal)((long)vpn << PAGESHIFT));
    }
    WriteRegister(REG_TLB_FLUSH, TLB_FLUSH_0);

    /* Zero BSS */
    memset((void *)(MEM_INVALID_SIZE + li.text_size + li.data_size),
           0, li.bss_size);

    /* Set entry point */
    p->user_pc = (void *)li.entry;
    if (info) info->pc = (void *)li.entry;

    /* Build argument list on new stack */
    *cpp++ = (char *)(unsigned long)argcount;
    cp2 = argbuf;
    for (i = 0; i < (int)argcount; i++) {
        *cpp++ = cp;
        strcpy(cp, cp2);
        cp  += strlen(cp) + 1;
        cp2 += strlen(cp2) + 1;
    }
    free(argbuf);
    *cpp++ = NULL;
    *cpp++ = NULL;
    *cpp   = 0;

    /* Set user mode */
    if (info) {
        info->psr = 0;
        for (i = 0; i < NUM_REGS; i++) info->regs[i] = 0;
    }

    TracePrintf(1, "LoadProgram '%s': success, entry=%p\n", name, (void*)li.entry);
    return 0;

no_mem:
    TracePrintf(0, "LoadProgram: out of physical memory for '%s'\n", name);
    free(argbuf);
    return -2;
}

/* =====================================================================
 *  KernelStart
 * ===================================================================== */

void KernelStart(ExceptionInfo *info, unsigned int pmem_size,
                 void *orig_brk, char **cmd_args)
{
    TracePrintf(0, "KernelStart: pmem_size=%u orig_brk=%p\n",
                pmem_size, orig_brk);

    kernel_brk  = orig_brk;
    vm_enabled  = 0;
    free_head   = -1;
    num_free    = 0;
    next_pid    = 0;
    num_procs   = 0;
    ready_head  = ready_tail = NULL;
    delay_head  = NULL;
    current     = NULL;
    idle_proc   = NULL;
    idle_started = 0;

    memset(proc_pool_used, 0, sizeof(proc_pool_used));
    memset(free_pfn, -1, sizeof(free_pfn));
    memset(tty_read_blocked,  0, sizeof(tty_read_blocked));
    memset(tty_inbuf,         0, sizeof(tty_inbuf));
    memset(tty_write_blocked, 0, sizeof(tty_write_blocked));
    memset(tty_transmitting,  0, sizeof(tty_transmitting));

    /* --- Set up interrupt vector table ---
     * MUST be static: after KernelStart returns, the hardware still uses
     * REG_VECTOR_BASE (a physical address) to dispatch traps.  A local
     * array would live on the kernel stack and be overwritten by subsequent
     * trap frames, causing random crashes.
     */
    static void (*ivt[TRAP_VECTOR_SIZE])(ExceptionInfo *);
    memset(ivt, 0, sizeof(ivt));
    ivt[TRAP_KERNEL]       = TrapKernel;
    ivt[TRAP_CLOCK]        = TrapClock;
    ivt[TRAP_ILLEGAL]      = TrapIllegal;
    ivt[TRAP_MEMORY]       = TrapMemory;
    ivt[TRAP_MATH]         = TrapMath;
    ivt[TRAP_TTY_RECEIVE]  = TrapTtyReceive;
    ivt[TRAP_TTY_TRANSMIT] = TrapTtyTransmit;
    for (int i = 7; i < TRAP_VECTOR_SIZE; i++) {
        if (ivt[i] == NULL) ivt[i] = TrapDummy;
    }

    WriteRegister(REG_VECTOR_BASE, (RCS421RegVal)ivt);

    /* --- Initialize free page list ---
     * Kernel occupies physical pages [VMEM_1_BASE/PAGESIZE, brk_page).
     * Pages below kernel (0 to VMEM_1_BASE/PAGESIZE-1) and above brk are free.
     */
    int total_pages = pmem_size >> PAGESHIFT;
    if (total_pages > MAX_PHYS_PAGES) total_pages = MAX_PHYS_PAGES;

    int kernel_start_pfn = VMEM_1_BASE >> PAGESHIFT;   /* = 512 */
    int kernel_end_pfn   = UP_TO_PAGE(orig_brk) >> PAGESHIFT;

    for (int pfn = 0; pfn < total_pages; pfn++) {
        if (pfn >= kernel_start_pfn && pfn < kernel_end_pfn) continue;
        pfn_free(pfn);
    }

    TracePrintf(0, "KernelStart: %d free pages (total %d)\n",
                num_free, total_pages);

    /* --- Build Region 1 (kernel) page table ---
     * Identity mapping: R1 VPN i → PFN (kernel_start_pfn + i).
     * Text pages: kprot = R|X, data/heap pages: kprot = R|W.
     * All uprot = NONE.
     */
    memset(kernel_pt, 0, sizeof(kernel_pt));

    int text_end_pfn  = (UP_TO_PAGE(&_etext) >> PAGESHIFT);
    int heap_end_pfn  = kernel_end_pfn;

    for (int i = 0; i < PAGE_TABLE_LEN; i++) {
        int pfn = kernel_start_pfn + i;
        long vaddr = VMEM_1_BASE + (long)i * PAGESIZE;
        (void)vaddr;

        if (pfn < text_end_pfn) {
            kernel_pt[i].valid = 1;
            kernel_pt[i].kprot = PROT_READ | PROT_EXEC;
            kernel_pt[i].uprot = PROT_NONE;
            kernel_pt[i].pfn   = pfn;
        } else if (pfn < heap_end_pfn) {
            kernel_pt[i].valid = 1;
            kernel_pt[i].kprot = PROT_READ | PROT_WRITE;
            kernel_pt[i].uprot = PROT_NONE;
            kernel_pt[i].pfn   = pfn;
        }
        /* Pages above heap: not mapped (will be mapped by SetKernelBrk) */
    }

    /* --- Create idle PCB ---
     * Idle has pid=0 and uses kernel-mode loop inside KernelStart.
     * We allocate its kernel stack physical pages now.
     */
    idle_proc = alloc_pcb();
    if (idle_proc == NULL) {
        TracePrintf(0, "KernelStart: failed to alloc idle PCB\n");
        Halt();
    }
    idle_proc->pid = 0;  /* Override: idle is always pid 0 */
    next_pid = 1;        /* init will be pid 1 */

    /* Allocate kernel stack pages for idle */
    {
        int ks_base_vpn = KERNEL_STACK_BASE >> PAGESHIFT;
        for (int i = 0; i < KERNEL_STACK_PAGES; i++) {
            int pfn = pfn_alloc();
            if (pfn == -1) {
                TracePrintf(0, "KernelStart: no pages for idle kstack\n");
                Halt();
            }
            int vpn = ks_base_vpn + i;
            idle_proc->r0pt[vpn].valid = 1;
            idle_proc->r0pt[vpn].kprot = PROT_READ | PROT_WRITE;
            idle_proc->r0pt[vpn].uprot = PROT_NONE;
            idle_proc->r0pt[vpn].pfn   = pfn;
        }
    }

    /* --- Create init PCB (pid=1) and build its R0 kernel stack --- */
    struct pcb *init_proc = alloc_pcb();
    if (init_proc == NULL) {
        TracePrintf(0, "KernelStart: failed to alloc init PCB\n");
        Halt();
    }
    /* init gets pid 1 (next_pid was 1 after idle used 0) */

    /* Allocate kernel stack pages for init */
    {
        int ks_base_vpn = KERNEL_STACK_BASE >> PAGESHIFT;
        for (int i = 0; i < KERNEL_STACK_PAGES; i++) {
            int pfn = pfn_alloc();
            if (pfn == -1) {
                TracePrintf(0, "KernelStart: no pages for init kstack\n");
                Halt();
            }
            int vpn = ks_base_vpn + i;
            init_proc->r0pt[vpn].valid = 1;
            init_proc->r0pt[vpn].kprot = PROT_READ | PROT_WRITE;
            init_proc->r0pt[vpn].uprot = PROT_NONE;
            init_proc->r0pt[vpn].pfn   = pfn;
        }
    }

    /* --- Set REG_PTR0 (init's R0), REG_PTR1 (kernel R1) --- */
    WriteRegister(REG_PTR0, (RCS421RegVal)(init_proc->r0pt));
    WriteRegister(REG_PTR1, (RCS421RegVal)kernel_pt);

    /* --- Enable virtual memory --- */
    WriteRegister(REG_VM_ENABLE, 1);
    vm_enabled = 1;
    TracePrintf(0, "KernelStart: VM enabled\n");

    /* --- Load init program ---
     * cmd_args[0] is the init program name.
     */
    current = init_proc;
    init_proc->state = PROC_RUNNING;

    char *init_name = (cmd_args != NULL && cmd_args[0] != NULL)
                      ? cmd_args[0] : "init";
    char *init_args[2] = { init_name, NULL };

    int rc = LoadProgram(init_name, init_args, init_proc, info);
    if (rc != 0) {
        TracePrintf(0, "KernelStart: LoadProgram('%s') failed: %d\n",
                    init_name, rc);
        Halt();
    }
    num_procs = 1;
    TracePrintf(0, "KernelStart: loaded init '%s' pid=%d\n",
                init_name, init_proc->pid);

    /* --- Load idle program ---
     * Try to load from "idle" binary; if not found, idle will use built-in
     * kernel-mode loop (ctx_valid = 0, user_pc / user_sp will be set).
     */
    {
        char *idle_args[2] = { "idle", NULL };
        /* Set REG_PTR0 to idle's R0 temporarily */
        WriteRegister(REG_PTR0, (RCS421RegVal)(idle_proc->r0pt));
        WriteRegister(REG_TLB_FLUSH, TLB_FLUSH_0);

        int idle_rc = LoadProgram("idle", idle_args, idle_proc, NULL);

        /* Restore init's R0 */
        WriteRegister(REG_PTR0, (RCS421RegVal)(init_proc->r0pt));
        WriteRegister(REG_TLB_FLUSH, TLB_FLUSH_0);

        if (idle_rc != 0) {
            TracePrintf(0, "KernelStart: idle load failed, using built-in idle\n");
            idle_proc->user_pc  = NULL;  /* marker: built-in mode */
            idle_proc->user_sp  = NULL;
            idle_proc->ctx_valid = 0;
        } else {
            TracePrintf(0, "KernelStart: loaded idle pid=%d\n", idle_proc->pid);
            idle_proc->ctx_valid = 0;  /* needs first-run bootstrap */
        }
    }

    /* --- Copy init's kernel stack to idle's kernel stack ---
     * This allows us to bootstrap idle's SavedContext correctly.
     * Map idle's kernel stack pages temporarily in R1 to write to them.
     */
    {
        int ks_base_vpn   = KERNEL_STACK_BASE >> PAGESHIFT;
        int r1_temp_base  = PAGE_TABLE_LEN - KERNEL_STACK_PAGES;

        for (int i = 0; i < KERNEL_STACK_PAGES; i++) {
            int idle_pfn = idle_proc->r0pt[ks_base_vpn + i].pfn;
            long temp_vaddr = VMEM_1_BASE + (long)(r1_temp_base + i) * PAGESIZE;

            kernel_pt[r1_temp_base + i].valid = 1;
            kernel_pt[r1_temp_base + i].kprot = PROT_READ | PROT_WRITE;
            kernel_pt[r1_temp_base + i].uprot = PROT_NONE;
            kernel_pt[r1_temp_base + i].pfn   = idle_pfn;
            WriteRegister(REG_TLB_FLUSH, (RCS421RegVal)temp_vaddr);

            /* Source: kernel stack in init's R0 (currently mapped) */
            void *src = (void *)((long)KERNEL_STACK_BASE + (long)i * PAGESIZE);
            void *dst = (void *)temp_vaddr;
            memcpy(dst, src, PAGESIZE);

            kernel_pt[r1_temp_base + i].valid = 0;
            WriteRegister(REG_TLB_FLUSH, (RCS421RegVal)temp_vaddr);
        }
    }

    /* --- Bootstrap idle's kernel context ---
     * ContextSwitch(DoSwitch, &idle->ctx, idle, NULL) saves current state
     * into idle->ctx (no actual switch). When we later restore idle->ctx,
     * execution resumes here with idle_started == 1 → idle enters Pause loop.
     */
    ContextSwitch(DoSwitch, &idle_proc->ctx, (void *)idle_proc, NULL);
    idle_proc->ctx_valid = 1;

    /* After ContextSwitch returns: are we idle resuming? */
    if (idle_started) {
        /* We're idle now. Enter kernel-mode idle loop. */
        TracePrintf(1, "Idle: entering Pause loop\n");
        while (1) {
            Pause();
        }
        /* Never reached */
    }
    idle_started = 1;

    /* --- Return from KernelStart → hardware runs init --- */
    /* info was modified by LoadProgram to point to init's entry/stack */
    current = init_proc;
    init_proc->state = PROC_RUNNING;

    TracePrintf(0, "KernelStart: returning to run init pid=%d\n",
                init_proc->pid);
}

/* =====================================================================
 *  Trap Handlers
 * ===================================================================== */

static void TrapDummy(ExceptionInfo *info) {
    (void)info;
}

/* ---------- TRAP_CLOCK ---------- */

static void TrapClock(ExceptionInfo *info) {
    (void)info;
    /* Tick delay queue */
    struct pcb *d = delay_head;
    struct pcb *prev = NULL;
    while (d != NULL) {
        struct pcb *n = d->next;
        d->delay_ticks--;
        if (d->delay_ticks <= 0) {
            /* Unblock */
            if (prev == NULL) delay_head = n;
            else              prev->next = n;
            d->next = NULL;
            enqueue_ready(d);
        } else {
            prev = d;
        }
        d = n;
    }

    clock_count++;
    /* Always preempt idle when something is ready; otherwise use 2-tick quantum */
    if (clock_count < 2 && current != idle_proc) return;
    clock_count = 0;

    struct pcb *from = current;
    struct pcb *to   = pick_next();

    if (to == from) return;

    /* Put from back on ready queue if it's a normal runnable process */
    if (from != idle_proc && from->state == PROC_RUNNING) {
        enqueue_ready(from);
    }

    do_context_switch(from, to);
}

/* ---------- TRAP_KERNEL (system calls) ---------- */

static void KernelFork(ExceptionInfo *info);
static void KernelExec(ExceptionInfo *info);
static void KernelExit(ExceptionInfo *info);
static void KernelWait(ExceptionInfo *info);
static void KernelGetPid(ExceptionInfo *info);
static void KernelBrk(ExceptionInfo *info);
static void KernelDelay(ExceptionInfo *info);
static void KernelTtyRead(ExceptionInfo *info);
static void KernelTtyWrite(ExceptionInfo *info);

static void TrapKernel(ExceptionInfo *info) {
    switch (info->code) {
    case YALNIX_FORK:    KernelFork(info);   break;
    case YALNIX_EXEC:    KernelExec(info);   break;
    case YALNIX_EXIT:    KernelExit(info);   break;
    case YALNIX_WAIT:    KernelWait(info);   break;
    case YALNIX_GETPID:  KernelGetPid(info); break;
    case YALNIX_BRK:     KernelBrk(info);    break;
    case YALNIX_DELAY:   KernelDelay(info);  break;
    case YALNIX_TTY_READ:  KernelTtyRead(info);  break;
    case YALNIX_TTY_WRITE: KernelTtyWrite(info); break;
    default:
        TracePrintf(0, "TrapKernel: unknown call %d\n", info->code);
        info->regs[0] = (unsigned long)ERROR;
        break;
    }
}

/* ---------- TRAP_ILLEGAL ---------- */

static void kill_current(int exit_status) {
    struct pcb *dying = current;
    dying->exit_status = exit_status;

    /* Notify parent */
    if (dying->parent != NULL) {
        struct pcb *par = dying->parent;
        dying->zombie_next = par->zombie_list;
        par->zombie_list   = dying;
        if (par->state == PROC_BLOCKED) {
            enqueue_ready(par);
        }
    } else {
        /* Orphan: don't free kstack now (still using it).  Just reclaim slot. */
        free_pcb(dying);
    }

    free_user_pages(dying);
    dying->state = PROC_ZOMBIE;
    num_procs--;
    if (num_procs <= 0 && ready_head == NULL) {
        TracePrintf(0, "Halting: no more processes\n");
        Halt();
    }

    struct pcb *next = pick_next();
    next->state = PROC_RUNNING;

    /* Switch to next using dying's R0 (kstack still valid after free_user_pages). */
    static struct pcb dead_from;
    memset(&dead_from, 0, sizeof(dead_from));
    dead_from.r0pt[0] = dying->r0pt[0]; /* dummy — not actually used for R0 switch */
    /* Set R0 to dying's PT so kernel stack remains accessible during save */
    WriteRegister(REG_PTR0, (RCS421RegVal)(dying->r0pt));
    WriteRegister(REG_TLB_FLUSH, TLB_FLUSH_0);
    ContextSwitch(DoSwitch, &dead_from.ctx, (void *)&dead_from, (void *)next);
    /* Never reached */
    Halt();
}

static void TrapIllegal(ExceptionInfo *info) {
    (void)info;
    TracePrintf(0, "TrapIllegal: pid=%d code=%d - killing process\n",
                current->pid, info->code);
    kill_current(ERROR);
}

/* ---------- TRAP_MEMORY ---------- */

static void TrapMemory(ExceptionInfo *info) {
    unsigned long addr = (unsigned long)info->addr;

    /* Is it a stack growth request? */
    unsigned long stk_limit = USER_STACK_LIMIT;
    unsigned long brk_limit = (unsigned long)current->user_brk_pg << PAGESHIFT;

    if (addr >= brk_limit + PAGESIZE &&  /* above break (with red zone) */
        addr < stk_limit &&              /* below user stack limit */
        addr >= MEM_INVALID_SIZE) {

        /* Grow stack to cover addr */
        int new_vpn = (int)(addr >> PAGESHIFT);
        int old_low = current->user_stk_low;

        for (int vpn = new_vpn; vpn < old_low; vpn++) {
            if (current->r0pt[vpn].valid) continue;
            int pfn = pfn_alloc();
            if (pfn == -1) {
                TracePrintf(0, "TrapMemory: out of memory growing stack\n");
                goto kill;
            }
            current->r0pt[vpn].valid = 1;
            current->r0pt[vpn].kprot = PROT_READ | PROT_WRITE;
            current->r0pt[vpn].uprot = PROT_READ | PROT_WRITE;
            current->r0pt[vpn].pfn   = pfn;
            WriteRegister(REG_TLB_FLUSH, (RCS421RegVal)((long)vpn << PAGESHIFT));
        }
        current->user_stk_low = new_vpn;
        return;  /* Resume */
    }

kill:
    TracePrintf(0, "TrapMemory: pid=%d addr=%p - killing\n",
                current->pid, info->addr);
    kill_current(ERROR);
    /* never reached */
}

/* ---------- TRAP_MATH ---------- */

static void TrapMath(ExceptionInfo *info) {
    TracePrintf(0, "TrapMath: pid=%d code=%d - killing\n",
                current->pid, info->code);
    (void)info;
    kill_current(ERROR);
}

/* ---------- TRAP_TTY_RECEIVE ---------- */

static void TrapTtyReceive(ExceptionInfo *info) {
    int tty = info->code;
    if (tty < 0 || tty >= NUM_TERMINALS) return;

    struct tty_line *line = (struct tty_line *)malloc(sizeof(struct tty_line));
    if (line == NULL) {
        TracePrintf(0, "TrapTtyReceive: out of memory\n");
        /* Receive anyway to clear hardware */
        char tmp[TERMINAL_MAX_LINE];
        TtyReceive(tty, tmp, TERMINAL_MAX_LINE);
        return;
    }
    line->len  = TtyReceive(tty, line->buf, TERMINAL_MAX_LINE);
    line->pos  = 0;
    line->next = NULL;

    /* Append to input buffer queue */
    if (tty_inbuf[tty] == NULL) {
        tty_inbuf[tty] = line;
    } else {
        struct tty_line *tail = tty_inbuf[tty];
        while (tail->next != NULL) tail = tail->next;
        tail->next = line;
    }

    /* Unblock any waiting reader */
    struct pcb *reader = tty_read_blocked[tty];
    if (reader != NULL) {
        tty_read_blocked[tty] = reader->next;
        reader->next = NULL;
        /* Complete the TtyRead: copy bytes to user buffer */
        struct tty_line *head = tty_inbuf[tty];
        if (head != NULL) {
            int want = reader->tty_len;
            int avail = head->len - head->pos;
            int give  = (want < avail) ? want : avail;
            memcpy(reader->tty_buf, head->buf + head->pos, give);
            head->pos += give;
            if (head->pos >= head->len) {
                tty_inbuf[tty] = head->next;
                free(head);
            }
            reader->tty_len = give;  /* reuse field as return value */
        }
        enqueue_ready(reader);
    }
}

/* ---------- TRAP_TTY_TRANSMIT ---------- */

static void TrapTtyTransmit(ExceptionInfo *info) {
    int tty = info->code;
    if (tty < 0 || tty >= NUM_TERMINALS) return;

    tty_transmitting[tty] = 0;

    struct pcb *writer = tty_write_blocked[tty];
    if (writer == NULL) return;

    int wrote = writer->tty_wrote;
    int total = writer->tty_len;

    if (wrote < total) {
        /* Current writer has more bytes to send */
        int remain = total - wrote;
        if (remain > TERMINAL_MAX_LINE) remain = TERMINAL_MAX_LINE;
        memcpy(writer->tty_kbuf, (char *)writer->tty_buf + wrote, remain);
        writer->tty_wrote  += remain;
        tty_transmitting[tty] = 1;
        TtyTransmit(tty, writer->tty_kbuf, remain);
        /* writer stays at head of queue */
    } else {
        /* Current writer is done: dequeue, wake it, start next writer */
        tty_write_blocked[tty] = writer->tty_write_next;
        writer->tty_write_next = NULL;
        writer->tty_len        = total;  /* return value = bytes written */
        enqueue_ready(writer);

        /* Start the next waiting writer (if any) */
        struct pcb *nxt = tty_write_blocked[tty];
        if (nxt != NULL) {
            tty_transmitting[tty] = 1;
            TtyTransmit(tty, nxt->tty_kbuf, nxt->tty_wrote);
        }
    }
}

/* =====================================================================
 *  Argument validation helpers
 * ===================================================================== */

/* Check that [buf, buf+len) is accessible in user mode with given prot */
static int check_user_buf(const void *buf, int len, int write) {
    if (buf == NULL && len == 0) return 0;
    if (buf == NULL) return -1;
    unsigned long start = (unsigned long)buf;
    unsigned long end   = start + len;
    if (start < MEM_INVALID_SIZE) return -1;
    if (end > VMEM_0_LIMIT) return -1;

    unsigned long vpn_start = start >> PAGESHIFT;
    unsigned long vpn_end   = (end - 1) >> PAGESHIFT;
    for (unsigned long vpn = vpn_start; vpn <= vpn_end; vpn++) {
        struct pte *pte = &current->r0pt[vpn];
        if (!pte->valid) return -1;
        if (write && !(pte->uprot & PROT_WRITE)) return -1;
        if (!write && !(pte->uprot & PROT_READ)) return -1;
    }
    return 0;
}

/* Check a null-terminated user string */
static int check_user_string(const char *s) {
    if (s == NULL) return -1;
    unsigned long addr = (unsigned long)s;
    while (1) {
        if (addr < MEM_INVALID_SIZE || addr >= VMEM_0_LIMIT) return -1;
        unsigned long vpn = addr >> PAGESHIFT;
        struct pte *pte = &current->r0pt[vpn];
        if (!pte->valid || !(pte->uprot & PROT_READ)) return -1;
        if (*(const char *)addr == '\0') return 0;
        addr++;
    }
}

/* =====================================================================
 *  Kernel Call Implementations
 * ===================================================================== */

/* ---------- GetPid ---------- */

static void KernelGetPid(ExceptionInfo *info) {
    info->regs[0] = (unsigned long)current->pid;
}

/* ---------- Delay ---------- */

static void KernelDelay(ExceptionInfo *info) {
    int ticks = (int)info->regs[1];
    if (ticks < 0) {
        info->regs[0] = (unsigned long)ERROR;
        return;
    }
    if (ticks == 0) {
        info->regs[0] = 0;
        return;
    }

    current->delay_ticks = ticks;
    current->state = PROC_BLOCKED;

    /* Insert into delay queue (sorted by delay_ticks) */
    struct pcb *prev = NULL, *d = delay_head;
    while (d != NULL && d->delay_ticks <= current->delay_ticks) {
        prev = d;
        d    = d->next;
    }
    current->next = d;
    if (prev == NULL) delay_head = current;
    else              prev->next = current;

    /* Schedule another process */
    struct pcb *next = pick_next();
    if (next == current) {
        /* Can't delay if no other process - just run */
        current->state = PROC_RUNNING;
        if (delay_head == current) delay_head = current->next;
        current->next = NULL;
        info->regs[0] = 0;
        return;
    }

    struct pcb *from = current;
    do_context_switch(from, next);
    /* When we return here, Delay has completed */
    info->regs[0] = 0;
}

/* ---------- Brk ---------- */

static void KernelBrk(ExceptionInfo *info) {
    void *addr = (void *)info->regs[1];
    int new_brk_pg = (int)(UP_TO_PAGE(addr) >> PAGESHIFT);
    int cur_brk_pg = current->user_brk_pg;

    /* Validate: must be above text/data, below stack red zone */
    int min_brk = MEM_INVALID_PAGES;  /* at least above invalid pages */
    int max_brk = current->user_stk_low - 1;  /* below stack */

    if (new_brk_pg < min_brk || new_brk_pg > max_brk) {
        info->regs[0] = (unsigned long)ERROR;
        return;
    }

    if (new_brk_pg > cur_brk_pg) {
        /* Grow */
        for (int vpn = cur_brk_pg; vpn < new_brk_pg; vpn++) {
            if (current->r0pt[vpn].valid) continue;
            int pfn = pfn_alloc();
            if (pfn == -1) {
                /* Roll back */
                for (int j = cur_brk_pg; j < vpn; j++) {
                    if (current->r0pt[j].valid) {
                        pfn_free(current->r0pt[j].pfn);
                        current->r0pt[j].valid = 0;
                        WriteRegister(REG_TLB_FLUSH,
                                      (RCS421RegVal)((long)j << PAGESHIFT));
                    }
                }
                info->regs[0] = (unsigned long)ERROR;
                return;
            }
            current->r0pt[vpn].valid = 1;
            current->r0pt[vpn].kprot = PROT_READ | PROT_WRITE;
            current->r0pt[vpn].uprot = PROT_READ | PROT_WRITE;
            current->r0pt[vpn].pfn   = pfn;
            WriteRegister(REG_TLB_FLUSH,
                          (RCS421RegVal)((long)vpn << PAGESHIFT));
        }
    } else if (new_brk_pg < cur_brk_pg) {
        /* Shrink */
        for (int vpn = new_brk_pg; vpn < cur_brk_pg; vpn++) {
            if (current->r0pt[vpn].valid) {
                pfn_free(current->r0pt[vpn].pfn);
                current->r0pt[vpn].valid = 0;
                WriteRegister(REG_TLB_FLUSH,
                              (RCS421RegVal)((long)vpn << PAGESHIFT));
            }
        }
    }

    current->user_brk_pg = new_brk_pg;
    info->regs[0] = 0;
}

/* ---------- Exit ---------- */

static void do_exit(struct pcb *dying, int status) {
    TracePrintf(1, "Exit: pid=%d status=%d\n", dying->pid, status);

    /* Orphan children (remove parent pointer) */
    for (int i = 0; i < MAX_PROCS; i++) {
        if (proc_pool_used[i] && proc_pool[i].parent == dying) {
            proc_pool[i].parent = NULL;
        }
    }

    /* Free zombie children (no one will collect them) */
    struct pcb *zc = dying->zombie_list;
    while (zc != NULL) {
        struct pcb *nxt = zc->zombie_next;
        free_all_r0_pages(zc);
        free_pcb(zc);
        zc = nxt;
    }
    dying->zombie_list = NULL;

    free_user_pages(dying);
    dying->exit_status = status;
    dying->state = PROC_ZOMBIE;
    num_procs--;

    struct pcb *par = dying->parent;
    if (par != NULL) {
        dying->zombie_next = par->zombie_list;
        par->zombie_list   = dying;

        if (par->state == PROC_BLOCKED) {
            /* Parent is in Wait() */
            enqueue_ready(par);
            par->state = PROC_READY;
        }
    } else {
        /* Orphan: we are still executing on dying's kernel stack, so we
         * MUST NOT free the kernel stack pages here.  free_user_pages()
         * already reclaimed user pages; just reclaim the PCB slot.
         * The 4 kernel-stack pages are a minor leak (acceptable for tests). */
        free_pcb(dying);
    }

    if (num_procs <= 0 && ready_head == NULL) {
        TracePrintf(0, "Halting: no more processes after exit pid=%d\n",
                    dying->pid);
        Halt();
    }
}

static void KernelExit(ExceptionInfo *info) {
    (void)info;
    int status = (int)info->regs[1];
    do_exit(current, status);
    /* do_exit may have called Halt() if no processes remain. */

    /* Switch to next process using kill_current-style dead-from trick. */
    struct pcb *dying = current;  /* still points to the dying pcb (state=ZOMBIE) */
    struct pcb *next  = pick_next();
    next->state = PROC_RUNNING;

    static struct pcb exit_dead;
    memset(&exit_dead, 0, sizeof(exit_dead));
    WriteRegister(REG_PTR0, (RCS421RegVal)(dying->r0pt));
    WriteRegister(REG_TLB_FLUSH, TLB_FLUSH_0);
    ContextSwitch(DoSwitch, &exit_dead.ctx, (void *)&exit_dead, (void *)next);
    Halt(); /* never reached */
}

/* ---------- Wait ---------- */

/* Collect one zombie child; returns child pid (or -1 if none). */
static int collect_zombie(struct pcb *p, int *status_ptr) {
    struct pcb *z = p->zombie_list;
    if (z == NULL) return -1;
    p->zombie_list = z->zombie_next;
    int zpid   = z->pid;
    int zstatus = z->exit_status;
    /* Children always have a parent, so do_exit used free_user_pages (kstack ok). */
    free_all_r0_pages(z);
    free_pcb(z);
    if (status_ptr != NULL) *status_ptr = zstatus;
    return zpid;
}

static void KernelWait(ExceptionInfo *info) {
    int *status_ptr = (int *)info->regs[1];

    /* Validate pointer */
    if (status_ptr != NULL &&
        check_user_buf(status_ptr, sizeof(int), 1) != 0) {
        info->regs[0] = (unsigned long)ERROR;
        return;
    }

    /* Check zombie list first */
    if (current->zombie_list != NULL) {
        info->regs[0] = (unsigned long)collect_zombie(current, status_ptr);
        return;
    }

    /* Check if we have any live children */
    int has_children = 0;
    for (int i = 0; i < MAX_PROCS; i++) {
        if (proc_pool_used[i] && proc_pool[i].parent == current) {
            has_children = 1;
            break;
        }
    }
    if (!has_children) {
        info->regs[0] = (unsigned long)ERROR;
        return;
    }

    /* Block until a child exits */
    current->state = PROC_BLOCKED;
    struct pcb *from = current;
    struct pcb *next = pick_next();
    do_context_switch(from, next);

    /* Woken by do_exit() enqueuing us */
    int zpid = collect_zombie(current, status_ptr);
    info->regs[0] = (zpid >= 0) ? (unsigned long)zpid : (unsigned long)ERROR;
}

/* ---------- Fork ---------- */

/*
 * Clone switch function: copies parent's R0 (page by page) to child,
 * then returns child's context.
 */
struct fork_args {
    struct pcb *child;
    struct pcb *parent;
};

static SavedContext *ForkSwitch(SavedContext *ctxp, void *p1, void *p2) {
    struct pcb *parent = (struct pcb *)p1;
    struct pcb *child  = (struct pcb *)p2;

    /* Save parent's context */
    parent->ctx = *ctxp;
    parent->ctx_valid = 1;

    /* Copy parent's R0 pages to child (except kernel stack - already set up) */
    int ks_low  = KERNEL_STACK_BASE >> PAGESHIFT;
    int ks_high = (KERNEL_STACK_LIMIT >> PAGESHIFT) - 1;

    for (int vpn = 0; vpn < PAGE_TABLE_LEN; vpn++) {
        if (vpn >= ks_low && vpn <= ks_high) continue;
        if (!parent->r0pt[vpn].valid) continue;

        /* Allocate child page */
        int pfn = pfn_alloc();
        if (pfn == -1) {
            /* Out of memory: mark child invalid, will be detected */
            child->r0pt[vpn].valid = 0;
            continue;
        }
        child->r0pt[vpn] = parent->r0pt[vpn];
        child->r0pt[vpn].pfn = pfn;

        /* Map child's page temporarily in R1 to do the copy */
        int r1_temp = PAGE_TABLE_LEN - 1;
        long temp_va = VMEM_1_BASE + (long)r1_temp * PAGESIZE;

        kernel_pt[r1_temp].valid = 1;
        kernel_pt[r1_temp].kprot = PROT_READ | PROT_WRITE;
        kernel_pt[r1_temp].uprot = PROT_NONE;
        kernel_pt[r1_temp].pfn   = pfn;
        WriteRegister(REG_TLB_FLUSH, (RCS421RegVal)temp_va);

        void *src = (void *)((long)vpn << PAGESHIFT);
